const savedToken = localStorage.getItem('dlms_auth_token');

const payload = {
    data: {
        serial_no: e.data.serial_no,
        serial_no: e.data.serial_no,
        casting_name: e.data.casting_name,
        casting: e.data.casting || null,
        heatname: e.data.heat_no || null
    },
    status: 'pending'
};

console.log('Payload:', payload);

fetch('https://dlms-api.iotnp.com/api/v1/templates/assembly_logsheet/submissions', {
    method: 'POST',
    headers: {
        'accept': 'application/json',
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${savedToken}`
    },
    body: JSON.stringify(payload)
})
.then(res => res.json())
.then(response => {
    console.log('Submission response:', response);
    if (response && (response._id || response.id || response.success)) {
        alert('Record submitted to Assembly Logsheet with status: Pending');
    } else {
        console.error('Unexpected response:', response);
        alert('Submission may have failed. Check console for details.');
    }
})
.catch(err => {
    console.error('Submit error:', err);
    alert('Submission failed. Please try again.');
});

