if (!window._serialValidation) {
  window._serialValidation = {
    timer: null,
    abortController: null,
    lastValue: null,
    lastResult: true
  };
}

const state = window._serialValidation;

if (!value || String(value).trim() === '') {
  return true;
}

const serialNumber = String(value).trim();

if (serialNumber === state.lastValue && state.lastResult !== null) {
  return state.lastResult;
}

if (state.abortController) {
  state.abortController.abort();
}

return new Promise((resolve) => {
  if (state.timer) {
    clearTimeout(state.timer);
  }

  state.timer = setTimeout(async () => {
    const savedToken = localStorage.getItem('dlms_auth_token');
    if (!savedToken) {
      state.lastValue = serialNumber;
      state.lastResult = true;
      resolve(true);
      return;
    }

    state.abortController = new AbortController();
    const signal = state.abortController.signal;

    try {
      const res = await fetch(
        `https://dlms-api.iotnp.com/api/v1/serial-numbers/check?serial_number=${encodeURIComponent(serialNumber)}`,
        {
          method: 'GET',
          headers: {
            'accept': 'application/json',
            'Authorization': `Bearer ${savedToken}`
          },
          signal
        }
      );
      const response = await res.json();
      const exists = response.exists === true;

      state.lastValue = serialNumber;
      state.lastResult = !exists;
      resolve(!exists);
    } catch (err) {
      if (err.name === 'AbortError') return;
      state.lastValue = serialNumber;
      state.lastResult = true;
      resolve(true);
    }
  }, 300);
});
